const claudeItems = $input.all();
const pgItems = $('PG: Pages without description').all();
const results = [];

for (let i = 0; i < claudeItems.length; i++) {
  const resp = claudeItems[i].json;
  const pg = pgItems[i] ? pgItems[i].json : {};
  const url = pg.url || '';

  if (resp.error) {
    results.push({ json: { ok: false, url, error: (resp.error.message||'api error').slice(0,80) } });
    continue;
  }

  try {
    let text = (resp.content || [])[0]?.text || '';
    text = text.replace(/```json\n?/gi,'').replace(/```\n?/g,'').trim();
    const d = JSON.parse(text);
    const esc = s => (s||'').replace(/'/g,"''");
    results.push({ json: {
      ok: true, url,
      description: esc((d.description||'').slice(0,200)),
      h1: esc((d.h1||'').slice(0,100))
    }});
  } catch(e) {
    results.push({ json: { ok: false, url, error: e.message } });
  }
}

return results;

const all = $input.all();
const ok = all.filter(i => i.json.id).length;
const total = all.length;
const errs = all.filter(i => !i.json.id && i.json.url).slice(0,3);
const date = new Date().toISOString().slice(0,10);
let msg = '✍️ WF-301 SEO Content\n\n';
msg += '✅ Записано: ' + ok + ' / ' + total + ' страниц\n';
if (errs.length) msg += '⚠️ Ошибок: ' + errs.length + '\n  ' + errs.map(e=>e.json.error||'no id').join(', ').slice(0,100) + '\n';
msg += '📅 ' + date;
return [{ json: { msg } }];
